import{_ as e,o as a,c as r,ag as d}from"./chunks/framework.Culc7SYV.js";const u=JSON.parse('{"title":"Scheduling","description":"","frontmatter":{},"headers":[],"relativePath":"Scheduling.md","filePath":"Scheduling.md","lastUpdated":1773806339000}'),s={name:"Scheduling.md"};function i(n,t,o,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="scheduling" tabindex="-1">Scheduling <a class="header-anchor" href="#scheduling" aria-label="Permalink to &quot;Scheduling&quot;">​</a></h1><p>Last modified: 17/03/2026</p><h2 id="fsrs-basics" tabindex="-1">FSRS Basics <a class="header-anchor" href="#fsrs-basics" aria-label="Permalink to &quot;FSRS Basics&quot;">​</a></h2><p>LearnKit uses <strong>FSRS</strong> (Free Spaced Repetition Scheduler).</p><p>FSRS chooses future review dates per card, based on your past answers and elapsed time.</p><h2 id="fsrs-model" tabindex="-1">FSRS Model <a class="header-anchor" href="#fsrs-model" aria-label="Permalink to &quot;FSRS Model&quot;">​</a></h2><p>Each card tracks 3 values:</p><table tabindex="0"><thead><tr><th>Value</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Stability</strong></td><td>How long memory lasts before dropping to target retention</td></tr><tr><td><strong>Difficulty</strong></td><td>How hard the card is for you (0–10)</td></tr><tr><td><strong>Retrievability</strong></td><td>Estimated chance (0–1) you can recall it right now</td></tr></tbody></table><p>When you rate a card, FSRS:</p><ol><li>Updates difficulty and stability.</li><li>Calculates a next interval to meet your requested retention.</li><li>Schedules the due date.</li></ol><p>In practice, easy cards get longer intervals; forgotten cards get shorter intervals.</p><h2 id="card-stages" tabindex="-1">Card Stages <a class="header-anchor" href="#card-stages" aria-label="Permalink to &quot;Card Stages&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Stage</th><th>Description</th></tr></thead><tbody><tr><td><strong>New</strong></td><td>Never reviewed</td></tr><tr><td><strong>Learning</strong></td><td>Early short-interval steps</td></tr><tr><td><strong>Review</strong></td><td>Main long-interval stage</td></tr><tr><td><strong>Relearning</strong></td><td>Short steps after a failed review</td></tr></tbody></table><h2 id="presets" tabindex="-1">Presets <a class="header-anchor" href="#presets" aria-label="Permalink to &quot;Presets&quot;">​</a></h2><p>Choose a preset in Settings -&gt; Study -&gt; Scheduling or set values manually:</p><table tabindex="0"><thead><tr><th>Preset</th><th>Learning steps</th><th>Relearning steps</th><th>Retention</th></tr></thead><tbody><tr><td>Relaxed</td><td>20 min</td><td>20 min</td><td>0.88</td></tr><tr><td>Balanced</td><td>10 min, 1 day</td><td>10 min</td><td>0.90</td></tr><tr><td>Aggressive</td><td>5 min, 30 min, 1 day</td><td>10 min</td><td>0.92</td></tr><tr><td>Custom</td><td><em>(user-defined)</em></td><td><em>(user-defined)</em></td><td><em>(user-defined)</em></td></tr></tbody></table><h3 id="manual-options" tabindex="-1">Manual Options <a class="header-anchor" href="#manual-options" aria-label="Permalink to &quot;Manual Options&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Learning steps</td><td><code>10, 1440</code></td><td>Minutes between learning steps (comma-separated)</td></tr><tr><td>Relearning steps</td><td><code>10</code></td><td>Minutes between relearning steps</td></tr><tr><td>Requested retention</td><td>0.90</td><td>Target recall probability (0.80–0.97)</td></tr></tbody></table><h3 id="setting-meaning" tabindex="-1">Setting Meaning <a class="header-anchor" href="#setting-meaning" aria-label="Permalink to &quot;Setting Meaning&quot;">​</a></h3><ul><li><strong>Learning steps</strong>: short intervals for new cards before they move to Review.</li><li><strong>Relearning steps</strong>: short intervals after an Again on a Review card.</li><li><strong>Requested retention</strong>: target recall when card is due.</li></ul><p>Higher retention increases workload (more frequent reviews). Lower retention reduces workload but increases forgetting.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>0.90</strong> is a strong default for most users.</p></div><h2 id="fsrs-log" tabindex="-1">FSRS Log <a class="header-anchor" href="#fsrs-log" aria-label="Permalink to &quot;FSRS Log&quot;">​</a></h2><p>You can inspect a card&#39;s FSRS history:</p><ol><li>Open the <a href="./Card-Browser">Card Browser</a>.</li><li>Select a card.</li><li>Open card details to see ratings, stability, difficulty, and interval calculations.</li></ol><p>Use this if a due date looks unexpected.</p><h2 id="reset-options" tabindex="-1">Reset Options <a class="header-anchor" href="#reset-options" aria-label="Permalink to &quot;Reset Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Button</th><th>Effect</th></tr></thead><tbody><tr><td>Reset scheduling</td><td>Reset all cards to <strong>New</strong> (clears intervals, stability, difficulty)</td></tr><tr><td>Reset analytics</td><td>Clear review history and heatmap data</td></tr></tbody></table><p>Both options are in Settings -&gt; Reset and cannot be undone.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./Study-Sessions">Study Sessions</a></li><li><a href="./Grading">Grading</a></li><li><a href="./Analytics">Analytics</a></li></ul>',31)])])}const p=e(s,[["render",i]]);export{u as __pageData,p as default};
